// Pull each `new()` ensures into the proof context so the two views land on
// the same concrete witness (Map::<K,ID>::empty()).
assert(r1@ == Map::<K,ID>::empty());
assert(r2@ == Map::<K,ID>::empty());

// Transitivity of `==` through the common witness gives r1@ == r2@.
assert(r1@ == r2@);

// Map extensionality fallback in case det_new_equal compares views via =~=.
assert(r1@ =~= r2@);
